// Node-RED Function node: ML4 decoder
// Outputs: 3 (CH01, CH02, CH03)

const Dev1 = "36xxxxxxxxxxxx01"  // jouw dev id CH01
const Dev2 = "36xxxxxxxxxxxx02"  // jouw dev id CH02
const Dev3 = "36xxxxxxxxxxxx03"  // jouw dev id CH03

const scaleBy1000 = [4200, 4300]
const ids = [4200, 4300, 4600, 4500]

const HEADER_LEN = 3

var buf = (typeof msg.payload === "string")
    ? Buffer.from(msg.payload, "base64")
    : msg.payload

if (!Buffer.isBuffer(buf) || buf.length < HEADER_LEN + 48) {
    node.error("Invalid payload - verwacht 51 bytes", msg)
    return null
}

function readF(off) {
    if (off + 4 > buf.length) return null
    const v = buf.readFloatBE(off)
    if (isNaN(v)) return null
    return Math.round(v * 100) / 100
}

const battery = (((buf[0] << 8) | buf[1]) & 0x7fff) / 1000

// 12 floats uitlezen
const values = []
for (let i = 0; i < 12; i++) {
    values.push(readF(HEADER_LEN + i * 4))
}

function buildDevice(dev, vals) {
    const d = {
        Dev: dev,
        TS: msg.time ? new Date(msg.time).toISOString() : new Date().toISOString(),
        ED: [],
        MD: []
    }

    for (let i = 0; i < ids.length; i++) {
        let val = vals[i]
        if (val != null) {
            if (scaleBy1000.includes(ids[i])) {
                val = Math.round((val / 1000) * 1000) / 1000
            }
            d.MD.push({ Id: ids[i], Val: val })
        }
    }

    d.MD.push({ Id: 7200, Val: battery })

    if (msg.snr !== undefined)
        d.MD.push({ Id: 5400, Val: parseFloat(msg.snr) })
    if (msg.rssi !== undefined)
        d.MD.push({ Id: 5500, Val: parseFloat(msg.rssi) })
    if (msg.dr?.spreadFactor !== undefined)
        d.MD.push({ Id: 5200, Val: parseFloat(msg.dr.spreadFactor) })

    return d
}

const mid = global.get("mid") || 0

const out1 = { ...msg, payload: { MID: mid, D: [buildDevice(Dev1, values.slice(0, 4))] } }
const out2 = { ...msg, payload: { MID: mid + 1, D: [buildDevice(Dev2, values.slice(4, 8))] } }
const out3 = { ...msg, payload: { MID: mid + 2, D: [buildDevice(Dev3, values.slice(8, 12))] } }

global.set("mid", mid + 3)

return [out1, out2, out3]
